import re, struct, zlib, itertools, math
from pathlib import Path
TOKEN_RE = re.compile(r"secret\{([0-9a-fA-F]{8})\}")


def iter_chunks(png_bytes):
    pos=8
    while pos+8<=len(png_bytes):
        length=struct.unpack('>I',png_bytes[pos:pos+4])[0]
        ctype=png_bytes[pos+4:pos+8]
        data=png_bytes[pos+8:pos+8+length]
        pos = pos+8+length+4
        yield ctype.decode('ascii','replace'), data


def paeth(a,b,c):
    p=a+b-c
    pa=abs(p-a); pb=abs(p-b); pc=abs(p-c)
    if pa<=pb and pa<=pc: return a
    if pb<=pc: return b
    return c


def decode_full(path):
    png=Path(path).read_bytes()
    width=height=channels=None
    idat=[]
    for ctype,data in iter_chunks(png):
        if ctype=='IHDR':
            width,height,bit_depth,color_type,_cm,_fm,interlace=struct.unpack('>IIBBBBB',data)
            channels=3 if color_type==2 else 4
        elif ctype=='IDAT':
            idat.append(data)
        elif ctype=='IEND':
            break
    stride=width*channels
    need=height*(stride+1)
    decomp=zlib.decompressobj(); buf=bytearray()
    for chunk in idat:
        buf.extend(decomp.decompress(chunk))
        if len(buf)>=need: break
    if len(buf)<need:
        raise RuntimeError('not enough')
    prev=bytearray(stride)
    pixels=bytearray(); off=0
    for _ in range(height):
        f=buf[off]; off+=1
        scan=buf[off:off+stride]; off+=stride
        recon=bytearray(stride)
        if f==0: recon[:] = scan
        elif f==1:
            for i in range(stride):
                left=recon[i-channels] if i>=channels else 0
                recon[i]=(scan[i]+left)&0xFF
        elif f==2:
            for i in range(stride):
                recon[i]=(scan[i]+prev[i])&0xFF
        elif f==3:
            for i in range(stride):
                left=recon[i-channels] if i>=channels else 0
                up=prev[i]
                recon[i]=(scan[i]+((left+up)>>1))&0xFF
        elif f==4:
            for i in range(stride):
                left=recon[i-channels] if i>=channels else 0
                up=prev[i]
                up_left=prev[i-channels] if i>=channels else 0
                recon[i]=(scan[i]+paeth(left,up,up_left))&0xFF
        pixels.extend(recon); prev=recon
    return width,height,channels,pixels


def pixel_value(pixels, width, height, channels, idx, seq, order):
    # idx is scan index
    if order=='row':
        r = idx // width; c = idx % width
    elif order=='row_rev':
        r = (height-1) - (idx // width); c = (width-1) - (idx % width)
    elif order=='col':
        c = idx // height; r = idx % height
    elif order=='col_rev':
        c = (width-1) - (idx // height); r = (height-1) - (idx % height)
    else:
        raise
    pix_index = (r*width + c)
    base = pix_index*channels
    # seq is list of channel indices
    out=[]
    for ch in seq:
        out.append(pixels[base+ch])
    return out


