import re, struct, base64, binascii, zlib, subprocess
from pathlib import Path

SECRET_RE=re.compile(rb'secret\{[0-9a-fA-F]{8}\}')
B64_RE=re.compile(rb'[A-Za-z0-9+/=]{12,}')

def parse_trailer(path):
    data=Path(path).read_bytes()
    if not data.startswith(b"\x89PNG\r\n\x1a\n"):
        return b''
    pos=8
    while pos+12<=len(data):
        ln=struct.unpack('>I',data[pos:pos+4])[0]
        typ=data[pos+4:pos+8]
        pos += 8
        pos += ln
        pos += 4
        if typ==b'IEND':
            break
    return data[pos:]

def find_in_bytes(blob):
    hits=set(SECRET_RE.findall(blob))
    # try base64 decoding whole blob
    stripped=re.sub(rb'\s+|\x00',b'',blob)
    if len(stripped)>=12:
        for enc in (stripped,):
            try:
                # add padding
                pad = b'='*((4-len(enc)%4)%4)
                dec=base64.b64decode(enc+pad, validate=False)
                hits |= set(SECRET_RE.findall(dec))
                try:
                    hits |= set(SECRET_RE.findall(zlib.decompress(dec)))
                except Exception:
                    pass
            except Exception:
                pass
    # try base64-looking substrings
    for m in B64_RE.finditer(blob):
        s=m.group(0)
        try:
            pad=b'='*((4-len(s)%4)%4)
            dec=base64.b64decode(s+pad, validate=False)
            hits |= set(SECRET_RE.findall(dec))
            try:
                hits |= set(SECRET_RE.findall(zlib.decompress(dec)))
            except Exception:
                pass
        except Exception:
            continue
    return sorted(hits)

imgs=['puzzle_0009.png','puzzle_0010.png','puzzle_0011.png','puzzle_0012.png']
